195	package body AxiStreamPkg is
196	
197	   function axiStreamMasterInit (constant config : AxiStreamConfigType) return AxiStreamMasterType is
198	      variable ret : AxiStreamMasterType;
199	   begin
200	      ret       := AXI_STREAM_MASTER_INIT_C;
201	      ret.tKeep := genTKeep(config);
202	      ret.tStrb := genTKeep(config);
203	      return ret;
204	   end function axiStreamMasterInit;
205	
206	   function axiStreamPacked (
207	      constant CONFIG_C : AxiStreamConfigType;
208	      axisMaster        : AxiStreamMasterType)
209	      return boolean is
210	   begin
211	      if (not allBits(axisMaster.tKeep(CONFIG_C.TDATA_BYTES_C-1 downto 0), '1')) then
212	         return false;
213	      end if;
214	      if (CONFIG_C.TSTRB_EN_C and
215	          not allBits(axisMaster.tStrb(CONFIG_C.TDATA_BYTES_C-1 downto 0), '1')) then
216	         return false;
217	      end if;
218	      return true;
219	   end function;
220	
221	   function axiStreamGetUserPos (
222	      axisConfig : AxiStreamConfigType;
223	      axisMaster : AxiStreamMasterType;
224	      bytePos    : integer := -1)
225	      return integer is
226	
227	      variable ret : integer;
228	   begin
229	
230	      if bytePos = -1 then
231	         ret := getTKeep(axisMaster.tKeep, axisConfig)-1;
232	         if (ret > axisConfig.TDATA_BYTES_C) then
233	            ret := axisConfig.TDATA_BYTES_C-1;
234	         end if;
235	         if ret < 0 then
236	            ret := 0;
237	         end if;
238	      else
239	         ret := bytePos;
240	      end if;
241	
242	      return(ret);
243	   end function;
244	
245	   function axiStreamGetUserField (
246	      axisConfig : AxiStreamConfigType;
247	      axisMaster : AxiStreamMasterType;
248	      bytePos    : integer := -1)
249	      return slv is
250	
251	      variable pos : integer;
252	      variable lsb : integer;
253	      variable ret : slv(maximum(axisConfig.TUSER_BITS_C-1, 0) downto 0);
254	   begin
255	
256	      pos := axiStreamGetUserPos(axisConfig, axisMaster, bytePos);
257	      lsb := axisConfig.TUSER_BITS_C*pos;
258	
259	      if axisConfig.TUSER_BITS_C > 0 then
260	         for i in 0 to AXI_STREAM_MAX_TDATA_WIDTH_C-ret'high-ret'low-1 loop
261	            if lsb = i then
262	               ret := axisMaster.tUser(ret'high+i downto ret'low+i);
263	            end if;
264	         end loop;
265	      else
266	         ret := (others => '0');
267	      end if;
268	
269	      -- Handle TUSER_BITS_C=0 case
270	      if (axisConfig.TUSER_BITS_C = 0 or axisConfig.TUSER_MODE_C = TUSER_NONE_C) then
271	         ret := (others => '0');
272	      end if;
273	
274	      return(ret);
275	   end function;
276	
277	   function axiStreamGetUserBit (
278	      axisConfig : AxiStreamConfigType;
279	      axisMaster : AxiStreamMasterType;
280	      bitPos     : integer;
281	      bytePos    : integer := -1)       -- -1 = last
282	      return sl is
283	
284	      variable user : slv(maximum(axisConfig.TUSER_BITS_C-1, 0) downto 0);
285	   begin
286	
287	      user := axiStreamGetuserField(axisConfig, axisMaster, bytePos);
288	      return(user(bitPos));
289	
290	   end function;
291	
292	   procedure axiStreamSetUserField (
293	      axisConfig : in    AxiStreamConfigType;
294	      axisMaster : inout AxiStreamMasterType;
295	      fieldValue : in    slv;
296	      bytePos    : in    integer := -1) is
297	
298	      variable pos : integer;
299	      variable lsb : integer;
300	   begin
301	
302	      pos := axiStreamGetUserPos(axisConfig, axisMaster, bytePos);
303	      lsb := axisConfig.TUSER_BITS_C*pos;
304	
305	      if (axisConfig.TUSER_BITS_C > 0 and axisConfig.TUSER_MODE_C /= TUSER_NONE_C) then
306	         axisMaster.tUser(fieldValue'high+lsb downto fieldValue'low+lsb) := fieldValue;
307	      else
308	         axisMaster.tUser := (others => '0');
309	      end if;
310	
311	   end procedure;
312	
313	   procedure axiStreamSetUserBit (
314	      axisConfig : in    AxiStreamConfigType;
315	      axisMaster : inout AxiStreamMasterType;
316	      bitPos     : in    integer;
317	      bitValue   : in    sl;
318	      bytePos    : in    integer := -1) is
319	
320	      variable pos : integer;
321	   begin
322	
323	      pos := axiStreamGetUserPos(axisConfig, axisMaster, bytePos);
324	
325	      axisMaster.tUser((axisConfig.TUSER_BITS_C*pos) + bitPos) := bitValue;
326	
327	   end procedure;
