354	   function ite (i : boolean; t : TKeepModeType; e : TKeepModeType) return TKeepModeType is
355	   begin
356	      if (i) then return t; else return e; end if;
357	   end function ite;
358	
359	   function genTKeep (bytes : natural range 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C) return slv is
360	      variable retVar : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
361	   begin
362	      retVar := (others => '0');
363	      for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
364	         if (bytes > i) then
365	            retVar(i) := '1';
366	         end if;
367	      end loop;
368	      return retVar;
369	   end function genTKeep;
370	
371	   function genTKeep (bytes : slv) return slv is
372	      variable retVar   : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
373	      variable bytesExt : slv(bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C)-1 downto 0);
374	   begin
375	      retVar   := (others => '0');
376	      bytesExt := resize(bytes, bytesExt'length);
377	      for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
378	         if (bytesExt >= toSlv(i+1, bytesExt'length)) then
379	            retVar(i) := '1';
380	         end if;
381	      end loop;
382	      return retVar;
383	   end function genTKeep;
384	
385	   function genTKeep (constant config : AxiStreamConfigType) return slv is
386	   begin
387	      -- Assumes TKEEP_MODE_C /= TKEEP_COUNT_C
388	      return genTKeep(config.TDATA_BYTES_C);
389	   end function genTKeep;
390	
391	   function getTKeep (tKeep : slv; axisConfig : AxiStreamConfigType) return natural is
392	      variable tKeepFull : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
393	      variable retVar    : natural;
394	   begin
395	      -- Init
396	      retVar    := 0;
397	      tKeepFull := resize(tKeep, AXI_STREAM_MAX_TKEEP_WIDTH_C);
398	      -- Check if TKEEP_MODE_C = TKEEP_COUNT_C
399	      if (axisConfig.TKEEP_MODE_C = TKEEP_COUNT_C) then
400	         retVar := conv_integer(tKeep(bitSize(axisConfig.TDATA_BYTES_C)-1 downto 0));
401	
402	      -- Check if TKEEP_MODE_C = TKEEP_FIXED_C
403	      elsif (axisConfig.TKEEP_MODE_C = TKEEP_FIXED_C) then
404	         -- TKEEP not used and using a full word every TXN
405	         retVar := axisConfig.TDATA_BYTES_C;
406	
407	      -- Else TKEEP_MODE_C is either TKEEP_NORMAL_C or TKEEP_COMP_C
408	      else
409	         for i in 0 to axisConfig.TDATA_BYTES_C-1 loop
410	            -- report "AxiStreamPkg::genTKeep( i:" & integer'image(i) & ")" severity warning;
411	            ----------------------------------------------------
412	            -- Confirmed in simulation the for loop ordering is:
413	            ----------------------------------------------------
414	            -- Warning: AxiStreamPkg::genTKeep( i:0)
415	            -- Warning: AxiStreamPkg::genTKeep( i:1)
416	            -- Warning: AxiStreamPkg::genTKeep( i:2)
417	            -- .....................................
418	            -- .....................................
419	            ----------------------------------------------------
420	            if (tKeepFull(i) = '1') then
421	               if (axisConfig.TKEEP_MODE_C = TKEEP_COMP_C) then
422	                  -- Assume LSBs are active when calculating active bytes in TKEEP_COMP_C mode
423	                  retVar := (i+1);
424	               else
425	                  -- TKEEP_NORMAL_C mode
426	                  retVar := retVar + 1;
427	               end if;
428	            end if;
429	         end loop;
430	      end if;
431	      return retVar;
432	   end function getTKeep;
433	
434	   procedure axiStreamSimSendTxn (
435	      constant CONFIG_C : in  AxiStreamConfigType;
436	      signal clk        : in  sl;
437	      signal master     : out AxiStreamMasterType;
438	      signal slave      : in  AxiStreamSlaveType;
439	      tData             : in  slv;
440	      tKeep             : in  slv                                          := "X";
441	      tLast             : in  sl                                           := '0';
442	      tDest             : in  slv(7 downto 0)                              := X"00";
443	      tId               : in  slv(7 downto 0)                              := X"00";
444	      tUser             : in  slv(AXI_STREAM_MAX_TDATA_WIDTH_C-1 downto 0) := (others => '0')) is
445	   begin
446	      -- Wait for rising edge
447	      wait until clk = '1';
448	
449	      -- Set the bus
450	      master        <= axiStreamMasterInit(CONFIG_C);
451	      master.tValid <= '1';
452	      master.tData  <= resize(tdata, AXI_STREAM_MAX_TDATA_WIDTH_C);
453	      if (tKeep /= "X") then
454	         master.tKeep <= resize(tkeep, AXI_STREAM_MAX_TKEEP_WIDTH_C);
455	      end if;
456	      master.tLast <= tlast;
457	      master.tDest <= tDest;
458	      master.tId   <= tid;
459	      master.tUser <= tUser;
460	
461	      -- Wait for tReady
462	      while (slave.tReady = '0') loop
463	         wait until clk = '1';
464	      end loop;
465	
466	   end procedure;
467	
468	   procedure axiStreamSimReceiveTxn (
469	      constant CONFIG_C : in  AxiStreamConfigType;
470	      signal clk        : in  sl;
471	      signal master     : in  AxiStreamMasterType;
472	      signal slave      : out AxiStreamSlaveType;
473	      tData             : out slv;
474	      tKeep             : out slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
475	      tLast             : out sl;
476	      tDest             : out slv(7 downto 0);
477	      tId               : out slv(7 downto 0);
478	      tUser             : out slv) is
479	   begin
480	      slave.tready <= '1';
481	
482	      -- Wait for rising edge
483	      while (master.tValid = '0') loop
484	         wait until clk = '1';
485	      end loop;
486	      -- Sample the bus
487	      tLast := master.tLast;
488	      tData := resize(master.tData, tData'length);
489	      tKeep := master.tKeep;
490	      tDest := master.tDest;
491	      tId   := master.tId;
492	      tUser := resize(master.tUser, tUser'length);
493	
494	   end procedure;
495	
496	   procedure axiStreamSimSendFrame (
497	      constant CONFIG_C : in  AxiStreamConfigType;
498	      signal clk        : in  sl;
499	      signal master     : out AxiStreamMasterType;
500	      signal slave      : in  AxiStreamSlaveType;
501	      data              : in  slVectorArray;
502	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
503	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
504	   is
505	      constant DATA_WIDTH_C : natural := data'length(1);
506	      constant DATA_BYTES_C : natural := wordCount(DATA_WIDTH_C, 8);
507	
508	      variable txWord  : slv(CONFIG_C.TDATA_BYTES_C*8-1 downto 0) := (others => '0');
509	      variable txKeep  : slv(CONFIG_C.TDATA_BYTES_C-1 downto 0)   := (others => '0');
510	      variable wordNum : integer;
511	   begin
512	      for i in data'range(1) loop
513	         wordNum                                                        := i mod CONFIG_C.TDATA_BYTES_C;
514	         txWord((wordNum+1)*DATA_WIDTH_C-1 downto wordNum*DATA_WIDTH_C) := muxSlVectorArray(data, i);
515	         txKeep((wordNum+1)*DATA_BYTES_C-1 downto wordNum*DATA_BYTES_C) := (others => '1');
516	
517	         if (wordNum = CONFIG_C.TDATA_BYTES_C-1) then
518	            axiStreamSimSendTxn(CONFIG_C, clk, master, slave, txWord, txKeep, toSl(i = data'high));
519	            txWord := (others => '0');
520	            txKeep := (others => '0');
521	         end if;
522	         wait until clk = '1';
523	         master.tValid <= '0';
524	      end loop;
525	   end procedure;
526	
527	   procedure axiStreamSimSendFrame (
528	      constant CONFIG_C : in  AxiStreamConfigType;
529	      signal clk        : in  sl;
530	      signal master     : out AxiStreamMasterType;
531	      signal slave      : in  AxiStreamSlaveType;
532	      data              : in  slv8Array;
533	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
534	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
535	   is
536	      variable vec : SlVectorArray(data'range, data(0)'range);
537	   begin
538	      for i in data'range loop
539	         for j in data(0)'range loop
540	            vec(i, j) := data(i)(j);
541	         end loop;
542	      end loop;
543	      axiStreamSimSendFrame(CONFIG_C, clk, master, slave, vec, tUserFirst, tUserLast);
544	   end procedure;
545	
546	   procedure axiStreamSimSendFrame (
547	      constant CONFIG_C : in  AxiStreamConfigType;
548	      signal clk        : in  sl;
549	      signal master     : out AxiStreamMasterType;
550	      signal slave      : in  AxiStreamSlaveType;
551	      data              : in  slv16Array;
552	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
553	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
554	   is
555	      variable vec : SlVectorArray(data'range, data(0)'range);
556	   begin
557	      for i in data'range loop
558	         for j in data(0)'range loop
559	            vec(i, j) := data(i)(j);
560	         end loop;
561	      end loop;
562	      axiStreamSimSendFrame(CONFIG_C, clk, master, slave, vec, tUserFirst, tUserLast);
563	   end procedure;
564	
565	   procedure axiStreamSimSendFrame (
566	      constant CONFIG_C : in  AxiStreamConfigType;
567	      signal clk        : in  sl;
568	      signal master     : out AxiStreamMasterType;
569	      signal slave      : in  AxiStreamSlaveType;
570	      data              : in  slv32Array;
571	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
572	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
573	   is
574	      variable vec : SlVectorArray(data'range, data(0)'range);
575	   begin
576	      for i in data'range loop
577	         for j in data(0)'range loop
578	            vec(i, j) := data(i)(j);
579	         end loop;
580	      end loop;
581	      axiStreamSimSendFrame(CONFIG_C, clk, master, slave, vec, tUserFirst, tUserLast);
582	   end procedure;
583	
584	   procedure axiStreamSimSendFrame (
585	      constant CONFIG_C : in  AxiStreamConfigType;
586	      signal clk        : in  sl;
587	      signal master     : out AxiStreamMasterType;
588	      signal slave      : in  AxiStreamSlaveType;
589	      data              : in  slv64Array;
590	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
591	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
592	   is
593	      variable vec : SlVectorArray(data'range, data(0)'range);
594	   begin
595	      for i in data'range loop
596	         for j in data(0)'range loop
597	            vec(i, j) := data(i)(j);
598	         end loop;
599	      end loop;
600	      axiStreamSimSendFrame(CONFIG_C, clk, master, slave, vec, tUserFirst, tUserLast);
601	   end procedure;
602	
603	   procedure axiStreamSimSendFrame (
604	      constant CONFIG_C : in  AxiStreamConfigType;
605	      signal clk        : in  sl;
606	      signal master     : out AxiStreamMasterType;
607	      signal slave      : in  AxiStreamSlaveType;
608	      data              : in  slv128Array;
609	      tUserFirst        : in  slv(7 downto 0) := (others => '0');
610	      tUserLast         : in  slv(7 downto 0) := (others => '0'))
611	   is
612	      variable vec : SlVectorArray(data'range, data(0)'range);
613	   begin
614	      for i in data'range loop
615	         for j in data(0)'range loop
616	            vec(i, j) := data(i)(j);
617	         end loop;
618	      end loop;
619	      axiStreamSimSendFrame(CONFIG_C, clk, master, slave, vec, tUserFirst, tUserLast);
620	   end procedure;
621	
622	   function getSlvSize (c : AxiStreamConfigType) return integer is
623	      variable size : integer := 1;
624	   begin
625	
626	      -- Data
627	      size := size + c.TDATA_BYTES_C*8;
628	
629	      -- Keep
630	      size := size + ite((c.TKEEP_MODE_C = TKEEP_NORMAL_C), c.TDATA_BYTES_C,  -- TKEEP_NORMAL_C
631	                         ite((c.TKEEP_MODE_C = TKEEP_COMP_C), bitSize(c.TDATA_BYTES_C-1),  -- TKEEP_COMP_C
632	                             ite((c.TKEEP_MODE_C = TKEEP_COUNT_C), bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C),  -- TKEEP_COUNT_C
633	                                 0)));  -- TKEEP_FIXED_C
634	
635	      -- User bits
636	      size := size + ite(c.TUSER_MODE_C = TUSER_FIRST_LAST_C, c.TUSER_BITS_C*2,
637	                         ite(c.TUSER_MODE_C = TUSER_LAST_C, c.TUSER_BITS_C,
638	                             ite(c.TUSER_MODE_C = TUSER_NORMAL_C, c.TDATA_BYTES_C * c.TUSER_BITS_C,
639	                                 0)));  -- TUSER_NONE_C
640	
641	      size := size + ite(c.TSTRB_EN_C, c.TDATA_BYTES_C, 0);  -- Strobe bits
642	      size := size + c.TDEST_BITS_C;
643	      size := size + c.TID_BITS_C;
644	
645	      return(size);
646	
647	   end function;
648	
649	   function toSlv (din : AxiStreamMasterType; c : AxiStreamConfigType) return slv is
650	      variable size     : integer              := getSlvSize(c);
651	      variable retValue : slv(size-1 downto 0) := (others => '0');
652	      variable i        : integer              := 0;
653	   begin
654	
655	      -- init, pass last
656	      assignSlv(i, retValue, din.tLast);
657	
658	      -- Pack data
659	      assignSlv(i, retValue, din.tData((c.TDATA_BYTES_C*8)-1 downto 0));
660	
661	      -- Pack keep
662	      if c.TKEEP_MODE_C = TKEEP_NORMAL_C then
663	         assignSlv(i, retValue, din.tKeep(c.TDATA_BYTES_C-1 downto 0));
664	      elsif c.TKEEP_MODE_C = TKEEP_COMP_C then
665	         -- Assume lsb is present
666	         assignSlv(i, retValue, toSlv(getTKeep(din.tKeep(c.TDATA_BYTES_C-1 downto 1), c), bitSize(c.TDATA_BYTES_C-1)));
667	      elsif c.TKEEP_MODE_C = TKEEP_COUNT_C then
668	         assignSlv(i, retValue, din.tKeep(bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C)-1 downto 0));
669	      end if;
670	      -- TKEEP_FIXED_C uses 0 bits
671	
672	      -- Pack user bits
673	      if (c.TUSER_BITS_C > 0 and c.TUSER_MODE_C /= TUSER_NONE_C) then
674	         if c.TUSER_MODE_C = TUSER_FIRST_LAST_C then
675	            assignSlv(i, retValue, resize(axiStreamGetUserField(c, din, 0), c.TUSER_BITS_C));  -- First byte
676	            assignSlv(i, retValue, resize(axiStreamGetUserField(c, din, -1), c.TUSER_BITS_C));  -- Last valid byte
677	
678	         elsif c.TUSER_MODE_C = TUSER_LAST_C then
679	            assignSlv(i, retValue, resize(axiStreamGetUserField(c, din, -1), c.TUSER_BITS_C));  -- Last valid byte
680	
681	         elsif c.TUSER_MODE_C = TUSER_NORMAL_C then
682	            for j in 0 to c.TDATA_BYTES_C-1 loop
683	               assignSlv(i, retValue, resize(axiStreamGetUserField(c, din, j), c.TUSER_BITS_C));
684	            end loop;
685	         end if;
686	      end if;
687	
688	      -- Strobe is optional
689	      if c.TSTRB_EN_C = true then
690	         assignSlv(i, retValue, din.tStrb(c.TDATA_BYTES_C-1 downto 0));
691	      end if;
692	
693	      -- Dest is optional
694	      if c.TDEST_BITS_C > 0 then
695	         assignSlv(i, retValue, din.tDest(c.TDEST_BITS_C-1 downto 0));
696	      end if;
697	
698	      -- Id is optional
699	      if c.TID_BITS_C > 0 then
700	         assignSlv(i, retValue, din.tId(c.TID_BITS_C-1 downto 0));
701	      end if;
702	
703	      return(retValue);
704	
705	   end function;
706	
707	   function toAxiStreamMaster (din : slv; valid : sl; c : AxiStreamConfigType) return AxiStreamMasterType is
708	      variable master : AxiStreamMasterType                        := axiStreamMasterInit(c);
709	      variable user   : slv(maximum(c.TUSER_BITS_C-1, 0) downto 0) := (others => '0');
710	      variable keep   : slv(bitSize(c.TDATA_BYTES_C-1)-1 downto 0);
711	      variable i      : integer                                    := 0;
712	   begin
713	
714	      -- Set valid,
715	      master.tValid := valid;
716	
717	      -- Set last
718	      assignRecord(i, din, master.tLast);
719	
720	      -- Get data
721	      assignRecord(i, din, master.tData((c.TDATA_BYTES_C*8)-1 downto 0));
722	
723	      -- Get keep bits
724	      if c.TKEEP_MODE_C = TKEEP_NORMAL_C then
725	         assignRecord(i, din, master.tKeep(c.TDATA_BYTES_C-1 downto 0));
726	      elsif c.TKEEP_MODE_C = TKEEP_COMP_C then
727	         assignRecord(i, din, keep);
728	         master.tKeep := genTKeep(conv_integer(keep)+1);
729	      elsif c.TKEEP_MODE_C = TKEEP_COUNT_C then
730	         assignRecord(i, din, master.tKeep(bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C)-1 downto 0));
731	      else                              -- KEEP_MODE_C = TKEEP_FIXED_C
732	         master.tKeep := genTKeep(c.TDATA_BYTES_C);
733	      end if;
734	
735	      -- get user bits
736	      if (c.TUSER_BITS_C > 0 and c.TUSER_MODE_C /= TUSER_NONE_C) then
737	         if c.TUSER_MODE_C = TUSER_FIRST_LAST_C then
738	            assignRecord(i, din, user);
739	            axiStreamSetUserField (c, master, resize(user, c.TUSER_BITS_C), 0);  -- First byte
740	
741	            assignRecord(i, din, user);
742	            axiStreamSetUserField (c, master, resize(user, c.TUSER_BITS_C), -1);  -- Last valid byte
743	
744	         elsif c.TUSER_MODE_C = TUSER_LAST_C then
745	            assignRecord(i, din, user);
746	            axiStreamSetUserField (c, master, resize(user, c.TUSER_BITS_C), -1);  -- Last valid byte
747	
748	         elsif (c.TUSER_MODE_C = TUSER_NORMAL_C) then
749	            for j in 0 to c.TDATA_BYTES_C-1 loop
750	               assignRecord(i, din, user);
751	               axiStreamSetUserField (c, master, resize(user, c.TUSER_BITS_C), j);
752	            end loop;
753	         end if;
754	      else
755	         user := (others => '0');
756	      end if;
757	
758	      -- Strobe is optional
759	      if c.TSTRB_EN_C = true then
760	         assignRecord(i, din, master.tStrb(c.TDATA_BYTES_C-1 downto 0));
761	      else
762	         master.tStrb := master.tKeep;  -- Strobe follows keep if unused
763	      end if;
764	
765	      -- Dest is optional
766	      if c.TDEST_BITS_C > 0 then
767	         assignRecord(i, din, master.tDest(c.TDEST_BITS_C-1 downto 0));
768	      end if;
769	
770	      -- ID is optional
771	      if c.TID_BITS_C > 0 then
772	         assignRecord(i, din, master.tId(c.TID_BITS_C-1 downto 0));
773	      end if;
774	
775	      return(master);
776	
777	   end function;
778	
779	end package body AxiStreamPkg;
780

